import React, { useEffect, useState } from 'react';
import api from '../services/api';

export default function Doctors(){
  const [doctors, setDoctors] = useState([]);
  const [form, setForm] = useState({name:'',specialization:'',contact:'',email:''});

  async function load(){
    const res = await api.get('/doctors');
    setDoctors(res.data);
  }
  useEffect(()=>{load()},[]);

  async function handleAdd(e){
    e.preventDefault();
    await api.post('/doctors', form);
    setForm({name:'',specialization:'',contact:'',email:''});
    load();
  }

  async function handleDelete(id){
    await api.delete(`/doctors/${id}`);
    load();
  }

  return (
    <div>
      <h2>Doctors</h2>
      <form className="form" onSubmit={handleAdd}>
        <input placeholder="Name" value={form.name} onChange={e=>setForm({...form,name:e.target.value})} required />
        <input placeholder="Specialization" value={form.specialization} onChange={e=>setForm({...form,specialization:e.target.value})} />
        <input placeholder="Contact" value={form.contact} onChange={e=>setForm({...form,contact:e.target.value})} />
        <input placeholder="Email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})} />
        <button className="btn">Add Doctor</button>
      </form>

      <table className="table">
        <thead><tr><th>ID</th><th>Name</th><th>Spec</th><th>Contact</th><th>Actions</th></tr></thead>
        <tbody>
          {doctors.map(d=> (
            <tr key={d.id}>
              <td>{d.id}</td>
              <td>{d.name}</td>
              <td>{d.specialization}</td>
              <td>{d.contact}</td>
              <td className="flex">
                <button className="btn secondary" onClick={()=>navigator.clipboard.writeText(d.id)}>Copy ID</button>
                <button className="btn" onClick={()=>handleDelete(d.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
